import chromadb
from chromadb.utils import embedding_functions
import re
from transformers import GPT2TokenizerFast
import Stemmer
import json
import random

CHROMA_PATH = "chroma_db"
COLLECTION_NAME = "handbook"

def main() -> None:
    stemmer = Stemmer.Stemmer("english")
    tokenizer = GPT2TokenizerFast.from_pretrained("Xenova/gpt-4", local_files_only=True)
    with open("extracted_output.txt", "r", encoding="utf-8") as file:
        text = file.read()
    blocks = [
    block.replace('"', '').strip()
    for block in re.split(r"(?=User:)", text)
    if block.strip().startswith("User:")
    ]
    saved_questions = []
    
    saved_answers = []
    CHUNK_SIZE = 32

    for question, answer in zip(blocks, ans):
        question_ids = tokenizer.encode(
            " ".join(stemmer.stemWords(question.split()))
        )

        answer_ids = tokenizer.encode(answer.strip()) + [tokenizer.eos_token_id]

        for start in range(0, len(answer_ids) - 1, CHUNK_SIZE):
            chunk = answer_ids[start:start + CHUNK_SIZE + 1]

            if len(chunk) < 2:
                continue

            left_ids = chunk[:-1]
            right_ids = chunk[1:]

            saved_questions.append(question_ids)
            saved_answers.append({
                "left": left_ids,
                "right": right_ids
            })

    


    print(len(saved_questions), len(saved_answers))
    with open("quetions.json", "w", encoding="utf-8") as out:
        json.dump(saved_questions, out, ensure_ascii=False, indent=2)
    with open("answer.json", "w", encoding="utf-8") as out:
        json.dump(saved_answers, out, ensure_ascii=False, indent=2)

    
if __name__ == "__main__":
    main()